using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly MulticlassClassificationMetrics _metrics;
    private readonly VBuffer<ReadOnlyMemory<char>> _slotNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 0);

        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on full data and cross-validate for metrics
        _model = pipeline.Fit(dataView);

        var crossValidationResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
        _metrics = crossValidationResults
            .OrderByDescending(r => r.Metrics.MacroAccuracy)
            .First().Metrics;

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract label slot names for confidence mapping
        var schema = _model.GetOutputSchema(dataView.Schema);
        var scoreColumn = schema.GetColumnOrNull("Score");
        if (scoreColumn.HasValue)
        {
            scoreColumn.Value.GetSlotNames(ref _slotNames);
        }
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        var names = _slotNames.DenseValues().ToArray();
        for (int i = 0; i < names.Length && i < prediction.Score.Length; i++)
        {
            confidence[names[i].ToString()] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationMetricsResponse GetMetrics()
    {
        var response = new EvaluationMetricsResponse
        {
            MacroAccuracy = _metrics.MacroAccuracy,
            MicroAccuracy = _metrics.MicroAccuracy,
            LogLoss = _metrics.LogLoss,
            LogLossReduction = _metrics.LogLossReduction,
        };

        for (int i = 0; i < _metrics.PerClassLogLoss.Count; i++)
        {
            var name = _slotNames.DenseValues().ElementAtOrDefault(i).ToString();
            response.PerCategory.Add(new CategoryMetric
            {
                Category = string.IsNullOrEmpty(name) ? $"Class {i}" : name,
                // ConfusionMatrix may not have per-class precision/recall with cross-validation
                // so we report what's available
                Precision = i < _metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? _metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                Recall = i < _metrics.ConfusionMatrix.PerClassRecall.Count
                    ? _metrics.ConfusionMatrix.PerClassRecall[i] : 0,
            });
        }

        return response;
    }
}

